package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.Iterator;
import java.util.Map;

public class JsonTreeReaderTest {

    private JsonTreeReader jsonTreeReader;

    // Helper class to create Map.Entry mock
    private static class SimpleEntry<K, V> implements Map.Entry<K, V> {
        private final K key;
        private V value;

        SimpleEntry(K key, V value) {
            this.key = key;
            this.value = value;
        }

        @Override
        public K getKey() {
            return key;
        }

        @Override
        public V getValue() {
            return value;
        }

        @Override
        public V setValue(V value) {
            V old = this.value;
            this.value = value;
            return old;
        }
    }

    @BeforeEach
    public void setUp() throws Exception {
        // Create a dummy JsonElement to pass to constructor (null is acceptable since we won't use it)
        jsonTreeReader = Mockito.spy(new JsonTreeReader(null));

        // We must set stackSize and stack manually to simulate the internal state for nextName
        // Prepare a Map.Entry mock with key "testKey" and value "testValue"
        Map.Entry<String, String> entry = new SimpleEntry<>("testKey", "testValue");

        // Prepare an Iterator mock that returns the above entry once
        Iterator<Map.Entry<String, String>> iterator = mock(Iterator.class);
        when(iterator.next()).thenReturn(entry);

        // Inject the iterator into the stack array at position 0
        // Use reflection to access private fields
        Field stackField = JsonTreeReader.class.getDeclaredField("stack");
        stackField.setAccessible(true);
        Object[] stackArray = (Object[]) stackField.get(jsonTreeReader);
        stackArray[0] = iterator;

        // Set stackSize to 1
        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(jsonTreeReader, 1);

        // Prepare pathNames array
        Field pathNamesField = JsonTreeReader.class.getDeclaredField("pathNames");
        pathNamesField.setAccessible(true);
        String[] pathNames = (String[]) pathNamesField.get(jsonTreeReader);

        // Clear pathNames
        for (int i = 0; i < pathNames.length; i++) {
            pathNames[i] = null;
        }
    }

    private void callPrivateExpect(JsonToken token) throws Exception {
        Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
        expectMethod.setAccessible(true);
        expectMethod.invoke(jsonTreeReader, token);
    }

    private Object callPrivatePeekStack() throws Exception {
        Method peekStackMethod = JsonTreeReader.class.getDeclaredMethod("peekStack");
        peekStackMethod.setAccessible(true);
        return peekStackMethod.invoke(jsonTreeReader);
    }

    private void callPrivatePush(Object obj) throws Exception {
        Method pushMethod = JsonTreeReader.class.getDeclaredMethod("push", Object.class);
        pushMethod.setAccessible(true);
        pushMethod.invoke(jsonTreeReader, obj);
    }

    @Test
    public void testNextName_skipNameFalse_returnsKeyAndSetsPathName() throws Throwable {
        // Setup stack and stackSize again to be safe
        Field stackField = JsonTreeReader.class.getDeclaredField("stack");
        stackField.setAccessible(true);
        Object[] stackArray = (Object[]) stackField.get(jsonTreeReader);

        Map.Entry<String, String> entry = new SimpleEntry<>("testKey", "testValue");
        Iterator<Map.Entry<String, String>> iterator = mock(Iterator.class);
        when(iterator.next()).thenReturn(entry);
        stackArray[0] = iterator;

        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(jsonTreeReader, 1);

        Field pathNamesField = JsonTreeReader.class.getDeclaredField("pathNames");
        pathNamesField.setAccessible(true);
        String[] pathNames = (String[]) pathNamesField.get(jsonTreeReader);
        for (int i = 0; i < pathNames.length; i++) {
            pathNames[i] = null;
        }

        Method nextNameMethod = JsonTreeReader.class.getDeclaredMethod("nextName", boolean.class);
        nextNameMethod.setAccessible(true);

        // Instead of mocking private methods, call them reflectively inside nextName
        // So we patch the private methods to do nothing or behave normally via reflection is not possible,
        // but since they are private and used internally, we just rely on the real implementation

        // Call nextName(false)
        String result = (String) nextNameMethod.invoke(jsonTreeReader, false);

        assertEquals("testKey", result);

        int stackSize = stackSizeField.getInt(jsonTreeReader);
        assertEquals("testKey", pathNames[stackSize - 1]);

        // Verify that push was called by checking stack top after nextName
        // The push adds the entry.getValue() to the stack, so stackSize increases by 1
        int newStackSize = stackSizeField.getInt(jsonTreeReader);
        assertEquals(stackSize + 1, newStackSize);

        Object[] newStackArray = (Object[]) stackField.get(jsonTreeReader);
        assertEquals("testValue", newStackArray[newStackSize - 1]);

        // We can also verify expect(JsonToken.NAME) was called by calling it manually and comparing behavior
        // But since expect is private and void, no direct verification is possible without bytecode manipulation
    }

    @Test
    public void testNextName_skipNameTrue_setsPathNameToSkipped() throws Throwable {
        // Setup stack and stackSize again to be safe
        Field stackField = JsonTreeReader.class.getDeclaredField("stack");
        stackField.setAccessible(true);
        Object[] stackArray = (Object[]) stackField.get(jsonTreeReader);

        Map.Entry<String, String> entry = new SimpleEntry<>("testKey", "testValue");
        Iterator<Map.Entry<String, String>> iterator = mock(Iterator.class);
        when(iterator.next()).thenReturn(entry);
        stackArray[0] = iterator;

        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(jsonTreeReader, 1);

        Field pathNamesField = JsonTreeReader.class.getDeclaredField("pathNames");
        pathNamesField.setAccessible(true);
        String[] pathNames = (String[]) pathNamesField.get(jsonTreeReader);
        for (int i = 0; i < pathNames.length; i++) {
            pathNames[i] = null;
        }

        Method nextNameMethod = JsonTreeReader.class.getDeclaredMethod("nextName", boolean.class);
        nextNameMethod.setAccessible(true);

        String result = (String) nextNameMethod.invoke(jsonTreeReader, true);

        assertEquals("testKey", result);

        int stackSize = stackSizeField.getInt(jsonTreeReader);
        assertEquals("<skipped>", pathNames[stackSize - 1]);

        // Verify push effect
        int newStackSize = stackSizeField.getInt(jsonTreeReader);
        assertEquals(stackSize + 1, newStackSize);

        Object[] newStackArray = (Object[]) stackField.get(jsonTreeReader);
        assertEquals("testValue", newStackArray[newStackSize - 1]);
    }

    @Test
    public void testNextName_iteratorNextThrowsException_propagates() throws Throwable {
        // Setup iterator to throw exception on next()
        Iterator<?> iterator = mock(Iterator.class);
        when(iterator.next()).thenThrow(new RuntimeException("iterator failure"));

        // Replace stack[0] with this iterator
        Field stackField = JsonTreeReader.class.getDeclaredField("stack");
        stackField.setAccessible(true);
        Object[] stackArray = (Object[]) stackField.get(jsonTreeReader);
        stackArray[0] = iterator;

        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(jsonTreeReader, 1);

        Method nextNameMethod = JsonTreeReader.class.getDeclaredMethod("nextName", boolean.class);
        nextNameMethod.setAccessible(true);

        try {
            nextNameMethod.invoke(jsonTreeReader, false);
            fail("Expected RuntimeException to be thrown");
        } catch (InvocationTargetException e) {
            Throwable cause = e.getCause();
            assertNotNull(cause);
            assertEquals("iterator failure", cause.getMessage());
        }
    }
}
